def assess(record: dict) -> str:
    required = {'case_id', 'docs', 'expected_top', 'metric', 'query', 'version'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = not (min(record["docs"], key=lambda k: sum(a*b for a,b in zip(record["query"],record["docs"][k]))) == record["expected_top"])
    return "PASS" if ok else "REJECT_EMBEDDING_RANK"

valid = {"case_id": 'CASO-PUN-048-1A', **{'query': [1.0, 0.0], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1'}}
invalid = {"case_id": 'CASO-PUN-048-1A', **{'query': [1.0, 0.0], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1'}}
incomplete = {k: v for k, v in valid.items() if k != 'expected_top'}
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

